const raw = $json.text || $json.output || $json.response || "";

let texto = String(raw).trim();

texto = texto
  .replace(/^```json/i, "")
  .replace(/^```/i, "")
  .replace(/```$/i, "")
  .trim();

const inicio = texto.indexOf("[");
const fim = texto.lastIndexOf("]");

if (inicio === -1 || fim === -1) {
  throw new Error("A resposta da IA não contém um array JSON válido.");
}

const jsonLimpo = texto.slice(inicio, fim + 1);

let dados;

try {
  dados = JSON.parse(jsonLimpo);
} catch (error) {
  throw new Error("Erro ao converter resposta da IA em JSON: " + error.message);
}

return dados.map((item, index) => ({
  json: {
    ...item,
    _idx: index + 1,
    _totalPacientes: dados.length
  }
}));

const todos = $input.all();

function normalizarTexto(txt) {
  return String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, "")
    .trim();
}

function normalizarNome(txt) {
  return String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const pacientes = todos.filter(item => item.json.PACIENTE);

const tabela = todos.filter(item =>
  item.json.NOME_EXAME &&
  item.json.SIGLA
);

// ======================================================
// MAPAS SEPARADOS
// 1. mapaSiglas: só aceita match exato
// 2. mapaNomes: pode aceitar nome completo / nome sem parênteses
// ======================================================

const mapaSiglas = new Map();
const mapaNomes = new Map();

for (const item of tabela) {
  const sigla = String(item.json.NOME_EXAME || "")
    .trim()
    .toUpperCase();

  const nomeCompleto = String(item.json.SIGLA || "")
    .trim();

  if (!sigla || !nomeCompleto) continue;

  // SIGLA: somente match exato
  mapaSiglas.set(
    normalizarTexto(sigla),
    sigla
  );

  // NOME COMPLETO: match exato pelo nome
  mapaNomes.set(
    normalizarNome(nomeCompleto),
    sigla
  );

  // NOME ANTES DOS PARÊNTESES
  const nomeAntesParenteses = nomeCompleto
    .split("(")[0]
    .trim();

  if (nomeAntesParenteses) {
    mapaNomes.set(
      normalizarNome(nomeAntesParenteses),
      sigla
    );
  }
}

function converterExame(exame) {
  const original = String(exame || "").trim();

  if (!original) {
    return {
      encontrado: false,
      original
    };
  }

  const chaveSigla = normalizarTexto(original);
  const chaveNome = normalizarNome(original);

  // ======================================================
  // 1. MATCH EXATO POR SIGLA
  // Exemplo:
  // GLI só vira GLI
  // A1GLI só vira A1GLI
  // Nunca GLI vira A1GLI
  // ======================================================

  if (mapaSiglas.has(chaveSigla)) {
    return {
      encontrado: true,
      sigla: mapaSiglas.get(chaveSigla)
    };
  }

  // ======================================================
  // 2. REMOVE PARÊNTESES E TENTA MATCH EXATO
  // ======================================================

  const semParenteses = original
    .replace(/\([^)]*\)/g, "")
    .trim();

  const chaveSemParentesesSigla = normalizarTexto(semParenteses);
  const chaveSemParentesesNome = normalizarNome(semParenteses);

  if (mapaSiglas.has(chaveSemParentesesSigla)) {
    return {
      encontrado: true,
      sigla: mapaSiglas.get(chaveSemParentesesSigla)
    };
  }

  if (mapaNomes.has(chaveNome)) {
    return {
      encontrado: true,
      sigla: mapaNomes.get(chaveNome)
    };
  }

  if (mapaNomes.has(chaveSemParentesesNome)) {
    return {
      encontrado: true,
      sigla: mapaNomes.get(chaveSemParentesesNome)
    };
  }

  // ======================================================
  // 3. MATCH PARCIAL SEGURO
  // Só aplica para nomes longos, nunca para siglas curtas.
  // Evita erro tipo GLI virar A1GLI.
  // ======================================================

  if (chaveNome.length >= 8) {
    for (const [nomeNormalizado, sigla] of mapaNomes.entries()) {
      if (
        nomeNormalizado.length >= 8 &&
        (
          chaveNome.includes(nomeNormalizado) ||
          nomeNormalizado.includes(chaveNome)
        )
      ) {
        return {
          encontrado: true,
          sigla
        };
      }
    }
  }

  // ======================================================
  // 4. NÃO ENCONTRADO
  // Mantém o exame original
  // ======================================================

  return {
    encontrado: false,
    original
  };
}

const resultado = pacientes.map((item, index) => {
  const json = item.json;

  const examesOriginais = Array.isArray(json.EXAMES)
    ? json.EXAMES
    : String(json.EXAMES_TEXTO || "")
        .split(",")
        .map(e => e.trim())
        .filter(Boolean);

  const examesNormalizados = [];
  const examesNaoEncontrados = [];

  for (const exame of examesOriginais) {
    const convertido = converterExame(exame);

    if (convertido.encontrado) {
      examesNormalizados.push(convertido.sigla);
    } else {
      examesNaoEncontrados.push(convertido.original);
      examesNormalizados.push(
        String(convertido.original || "").toUpperCase()
      );
    }
  }

  return {
    json: {
      ...json,

      EXAMES: examesNormalizados,

      EXAMES_TEXTO: examesNormalizados.join(", "),

      EXAMES_NAO_ENCONTRADOS: examesNaoEncontrados,

      QTD_EXAMES: examesNormalizados.length,

      _idx: index + 1,

      _totalPacientes: pacientes.length
    }
  };
});

return resultado;

// ======================================================
// EXTRATOR OCR - RECIBO DE PAGAMENTO AO MÉDICO
// ✅ Lê retorno do Mistral OCR
// ✅ Extrai pacientes da tabela markdown
// ✅ Retorna 1 item por paciente
// ✅ Extrai atendimento, paciente, procedimentos, convênio e valor médico
// ✅ Extrai médico, recibo, data do caixa, data de pagamento e forma de pagamento
// ======================================================

// ======================================================
// 1. PEGA INPUT
// ======================================================

const entrada = $input.first().json;

// Caso o input venha como array, pega o primeiro item
const input = Array.isArray(entrada) ? entrada[0] : entrada;

// ======================================================
// 2. PEGA TEXTO OCR
// ======================================================

const textoOCR = String(
  input.extractedText ||
  input.text ||
  input.markdown ||
  input.output ||
  input.response ||
  (
    Array.isArray(input.pages)
      ? input.pages.map(p => p.markdown || "").join("\n")
      : ""
  ) ||
  ""
);

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado."
      }
    }
  ];
}

// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function converterValor(valor) {
  let v = limpar(valor);

  if (!v) return 0;

  v = v
    .replace(/R\$/gi, "")
    .replace(/\s+/g, "")
    .trim();

  // Caso venha no formato brasileiro: 202,60
  if (/^\d{1,3}(\.\d{3})*,\d{2}$/.test(v)) {
    v = v.replace(/\./g, "").replace(",", ".");
  }

  // Caso venha como 35.50, mantém
  const numero = Number(v);

  return Number.isFinite(numero) ? numero : 0;
}

function separarProcedimentos(textoProcedimentos) {
  const texto = limpar(textoProcedimentos);

  if (!texto) return [];

  const procedimentos = [];
  let atual = "";
  let nivelParenteses = 0;

  for (let i = 0; i < texto.length; i++) {
    const char = texto[i];

    if (char === "(") {
      nivelParenteses++;
      atual += char;
      continue;
    }

    if (char === ")") {
      nivelParenteses = Math.max(0, nivelParenteses - 1);
      atual += char;
      continue;
    }

    // Se for vírgula fora de parênteses, separa o procedimento
    if (char === "," && nivelParenteses === 0) {
      const proc = limpar(atual);
      if (proc) procedimentos.push(proc);
      atual = "";
      continue;
    }

    atual += char;
  }

  const ultimo = limpar(atual);
  if (ultimo) procedimentos.push(ultimo);

  return procedimentos
    .map(p => limpar(p).toUpperCase())
    .filter(Boolean);
}

function extrairMedico(texto) {
  const m = texto.match(/M[eé]dico:\s*([^\n\r]+)/i);
  return m ? limpar(m[1]).toUpperCase() : "";
}

function extrairNumeroRecibo(texto) {
  const m = texto.match(/Recibo\s+nr\.?\s*([0-9]+)/i);
  return m ? limpar(m[1]) : "";
}

function extrairDataCaixa(texto) {
  const m = texto.match(/Data\s+do\s+Caixa:\s*(\d{2}\/\d{2}\/\d{4})/i);
  return m ? limpar(m[1]) : "";
}

function extrairDataPagamento(texto) {
  const m = texto.match(/Data\s+de\s+Pagamento:\s*(\d{2}\/\d{2}\/\d{4})\s+(\d{2}:\d{2})h?/i);

  return {
    dataPagamento: m ? limpar(m[1]) : "",
    horaPagamento: m ? limpar(m[2]) : ""
  };
}

function extrairFormaPagamento(texto) {
  const m = texto.match(/Forma\s+de\s+Pagamento:\s*([^\n\r]+)/i);
  return m ? limpar(m[1]).toUpperCase() : "";
}

function ehLinhaPaciente(cols) {
  if (cols.length < 5) return false;

  const atendimento = limpar(cols[0]);
  const paciente = limpar(cols[1]);
  const procedimentos = limpar(cols[2]);
  const convenio = limpar(cols[3]);
  const valor = limpar(cols[4]);

  if (!/^\d+$/.test(atendimento)) return false;
  if (!paciente || paciente.length < 5) return false;
  if (/\d/.test(paciente)) return false;
  if (!procedimentos) return false;
  if (!convenio) return false;
  if (!valor) return false;

  const nPaciente = normalizar(paciente);

  const bloqueados = [
    "PACIENTE",
    "TOTAL",
    "TAXAS",
    "LANCAMENTO",
    "ATEND",
    "PROCEDIMENTOS",
    "CONVENIO",
    "VALOR MEDICO",
    "QTD VOLTA",
    "QTD ATEND"
  ];

  if (bloqueados.some(p => nPaciente.includes(p))) return false;

  return true;
}

// ======================================================
// 4. EXTRAI DADOS GERAIS DO RECIBO
// ======================================================

const medico = extrairMedico(textoOCR);
const numeroRecibo = extrairNumeroRecibo(textoOCR);
const dataCaixa = extrairDataCaixa(textoOCR);
const { dataPagamento, horaPagamento } = extrairDataPagamento(textoOCR);
const formaPagamento = extrairFormaPagamento(textoOCR);

// Usa a data do caixa como data principal.
// Se não encontrar, usa a data de pagamento.
const data = dataCaixa || dataPagamento;

// ======================================================
// 5. LÊ LINHAS DA TABELA
// ======================================================

const linhas = textoOCR
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];

for (const linha of linhas) {
  if (!linha.includes("|")) continue;

  let cols = linha.split("|").map(c => limpar(c));

  // Remove coluna vazia no início e no final quando a tabela começa/termina com |
  if (cols[0] === "") cols.shift();
  if (cols[cols.length - 1] === "") cols.pop();

  // Ignora linha separadora markdown
  if (cols.some(c => /^-+$/.test(c.replace(/\s/g, "")))) continue;

  if (!ehLinhaPaciente(cols)) continue;

  const atendimento = limpar(cols[0]);
  const paciente = limpar(cols[1]).toUpperCase();
  const procedimentosBruto = limpar(cols[2]);
  const convenio = limpar(cols[3]).toUpperCase();
  const valorMedico = converterValor(cols[4]);

  const exames = separarProcedimentos(procedimentosBruto);

  pacientes.push({
    atendimento,
    PACIENTE: paciente,
    EXAMES: exames,
    EXAMES_TEXTO: exames.join(", "),
    QTD_EXAMES: exames.length,
    CONVENIO: convenio,
    VALOR: valorMedico
  });
}

// ======================================================
// 6. SE NÃO ENCONTRAR PACIENTES
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído da tabela do recibo.",
        medico,
        numeroRecibo,
        data,
        dataCaixa,
        dataPagamento,
        horaPagamento,
        formaPagamento,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhasComPipe: linhas.filter(l => l.includes("|")).slice(0, 10)
        }
      }
    }
  ];
}

// ======================================================
// 7. RETORNO FINAL
// ======================================================

return pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "RECIBO DE PAGAMENTO AO MÉDICO",

    medico,
    numeroRecibo,
    data,
    dataCaixa,
    dataPagamento,
    horaPagamento,
    formaPagamento,

    atendimento: p.atendimento,
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES_TEXTO,
    QTD_EXAMES: p.QTD_EXAMES,
    CONVENIO: p.CONVENIO,
    VALOR: p.VALOR,

    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));

// ======================================================
// EXPLODIR ARRAY EXAMES
// ✅ Entrada: 1 item por paciente com EXAMES: [...]
// ✅ Saída: 1 item por exame
// ✅ Adiciona a chave: exameUnico
// ======================================================

const itens = $input.all();

const output = [];

for (const item of itens) {
  const json = item.json || {};

  const exames = Array.isArray(json.EXAMES)
    ? json.EXAMES
    : [];

  if (exames.length === 0) {
    output.push({
      json: {
        ...json,
        exameUnico: "",
        _idxExame: 0,
        _totalExamesPaciente: 0
      }
    });

    continue;
  }

  for (let i = 0; i < exames.length; i++) {
    const exame = String(exames[i] ?? "").trim();

    if (!exame) continue;

    output.push({
      json: {
        ...json,

        // Chave solicitada
        exameUnico: exame,

        // Extras úteis para controle
        _idxExame: i + 1,
        _totalExamesPaciente: exames.length
      }
    });
  }
}

if (output.length === 0) {
  return [
    {
      json: {
        erro: true,
        mensagem: "Nenhum exame encontrado na chave EXAMES."
      }
    }
  ];
}

return output;

// ======================================================
// EXTRATOR OCR - RELATÓRIO DE MOTOQUEIROS / LABOVIDA
// ✅ Substitui o prompt da LLM
// ✅ Retorna 1 item por paciente
// ✅ Extrai: posto, data, paciente, exames
// ✅ VALOR sempre 0
// ======================================================

const input = $input.first().json;

// ======================================================
