// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function extrairPosto(nomeArquivo, texto) {
  const fonte = `${nomeArquivo || ""}\n${texto || ""}`;

  // Exemplo: P158, P 158, P0158
  let m = fonte.match(/\bP\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  // Exemplo: Posto 158
  m = fonte.match(/\bPOSTO\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  return "";
}

function extrairData(nomeArquivo, texto) {
  const fonte = `${nomeArquivo || ""}\n${texto || ""}`;

  // Nome do arquivo: DIA 19.05.2026
  let m = fonte.match(/\b(\d{2})\.(\d{2})\.(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // Texto: 19/05/2026
  m = fonte.match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // Texto: 19-05-2026
  m = fonte.match(/\b(\d{2})-(\d{2})-(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  return "";
}

function removerColchetes(texto) {
  return String(texto || "")
    .replace(/\[[^\]]*]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function ehDataBR(valor) {
  return /^\d{2}\/\d{2}\/\d{4}$/.test(limpar(valor));
}

function ehCodigo(valor) {
  return /^\d{4,}$/.test(limpar(valor));
}

function ehNomePaciente(valor) {
  const texto = limpar(valor);
  const n = normalizar(texto);

  if (!texto) return false;
  if (texto.length < 5) return false;
  if (/\d/.test(texto)) return false;

  const bloqueados = [
    "LABOVIDA",
    "RELATORIO",
    "RELATÓRIO",
    "MOTOQUEIROS",
    "RESUMO",
    "PACIENTES",
    "EXAME",
    "EXAMES",
    "USUARIO",
    "USUÁRIO",
    "DATA DE IMPRESSAO",
    "DATA DE IMPRESSÃO"
  ];

  return !bloqueados.some(b => n.includes(normalizar(b)));
}

function separarExames(textoExames, posto) {
  let texto = removerColchetes(textoExames);

  if (!texto) return [];

  // Regra específica: se P137 e vier GLICOSE JEJUM, retorna GLI
  if (String(posto) === "137") {
    texto = texto.replace(/\bGLICOSE\s+JEJUM\b/gi, "GLI");
  }

  // Neste relatório de motoqueiros os exames vêm separados por espaço
  return texto
    .split(/\s+/)
    .map(e => limpar(e))
    .filter(e => e)
    .filter(e => !/^\d+([.,]\d+)?$/.test(e));
}

function linhaIgnorada(linha) {
  const n = normalizar(linha);

  if (!n) return true;
  if (n.includes("---")) return true;
  if (n.includes("LABOVIDA")) return true;
  if (n.includes("RELATORIO DE MOTOQUEIROS")) return true;
  if (n.includes("RESUMO")) return true;
  if (n.includes("PACIENTES")) return true;
  if (n.includes("EXAME(S)")) return true;
  if (n.includes("DATA DE IMPRESSAO")) return true;
  if (n.includes("USUARIO")) return true;

  return false;
}

// ======================================================
// 4. DADOS BASE
// ======================================================

const posto = extrairPosto(nomeArquivo, textoOCR);
const dataPadrao = extrairData(nomeArquivo, textoOCR);

// ======================================================
// 5. PROCESSA LINHAS DA TABELA
// Formato esperado:
// | 19/05/2026 | 12234537 | JOÃO ... | 25OHD AUR B12 ... |
// ======================================================

const linhas = textoOCR
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];

for (const linha of linhas) {
  if (!linha.includes("|")) continue;
  if (linhaIgnorada(linha)) continue;

  let cols = linha.split("|").map(c => limpar(c));

  // Remove bordas vazias quando a linha começa/termina com |
  if (cols[0] === "") cols.shift();
  if (cols[cols.length - 1] === "") cols.pop();

  if (cols.length < 4) continue;

  const dataLinha = limpar(cols[0]);
  const codigo = limpar(cols[1]);
  const paciente = limpar(cols[2]);
  const examesBruto = limpar(cols[3]);

  if (!ehDataBR(dataLinha)) continue;
  if (!ehCodigo(codigo)) continue;
  if (!ehNomePaciente(paciente)) continue;
  if (!examesBruto) continue;

  const exames = separarExames(examesBruto, posto);

  if (exames.length === 0) continue;

  pacientes.push({
    data: dataLinha || dataPadrao,
    codigo,
    PACIENTE: paciente.toUpperCase(),
    EXAMES: exames
  });
}

// ======================================================
// 6. RETORNO FINAL
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído do OCR.",
        posto,
        data: dataPadrao,
        nomeArquivo,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhasComPipe: linhas.filter(l => l.includes("|")).slice(0, 10)
        }
      }
    }
  ];
}

return pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "(+)COMPUTADOR DO POSTO",
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES.join(", "),
    QTD_EXAMES: p.EXAMES.length,
    VALOR: 0,
    posto,
    data: p.data || dataPadrao,
    codigo: p.codigo,
    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));

// ======================================================
// EXPLODIR ARRAY EXAMES
// ✅ Retorna 1 item por exame
// ✅ Adiciona a chave exameUnico
// ======================================================

const itens = $input.all();
const output = [];

for (const item of itens) {
