const todos = $input.all();

function normalizarTexto(txt) {
  return String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, "")
    .trim();
}

function normalizarNome(txt) {
  return String(txt || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase()
    .replace(/[^A-Z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const pacientes = todos.filter(item => item.json.PACIENTE);

const tabela = todos.filter(item =>
  item.json.NOME_EXAME &&
  item.json.SIGLA
);

// ======================================================
// MAPAS SEPARADOS
// 1. mapaSiglas: só aceita match exato
// 2. mapaNomes: pode aceitar nome completo / nome sem parênteses
// ======================================================

const mapaSiglas = new Map();
const mapaNomes = new Map();

for (const item of tabela) {
  const sigla = String(item.json.NOME_EXAME || "")
    .trim()
    .toUpperCase();

  const nomeCompleto = String(item.json.SIGLA || "")
    .trim();

  if (!sigla || !nomeCompleto) continue;

  // SIGLA: somente match exato
  mapaSiglas.set(
    normalizarTexto(sigla),
    sigla
  );

  // NOME COMPLETO: match exato pelo nome
  mapaNomes.set(
    normalizarNome(nomeCompleto),
    sigla
  );

  // NOME ANTES DOS PARÊNTESES
  const nomeAntesParenteses = nomeCompleto
    .split("(")[0]
    .trim();

  if (nomeAntesParenteses) {
    mapaNomes.set(
      normalizarNome(nomeAntesParenteses),
      sigla
    );
  }
}

function converterExame(exame) {
  const original = String(exame || "").trim();

  if (!original) {
    return {
      encontrado: false,
      original
    };
  }

  const chaveSigla = normalizarTexto(original);
  const chaveNome = normalizarNome(original);

  // ======================================================
  // 1. MATCH EXATO POR SIGLA
  // Exemplo:
  // GLI só vira GLI
  // A1GLI só vira A1GLI
  // Nunca GLI vira A1GLI
  // ======================================================

  if (mapaSiglas.has(chaveSigla)) {
    return {
      encontrado: true,
      sigla: mapaSiglas.get(chaveSigla)
    };
  }

  // ======================================================
  // 2. REMOVE PARÊNTESES E TENTA MATCH EXATO
  // ======================================================

  const semParenteses = original
    .replace(/\([^)]*\)/g, "")
    .trim();

  const chaveSemParentesesSigla = normalizarTexto(semParenteses);
  const chaveSemParentesesNome = normalizarNome(semParenteses);

  if (mapaSiglas.has(chaveSemParentesesSigla)) {
    return {
      encontrado: true,
      sigla: mapaSiglas.get(chaveSemParentesesSigla)
    };
  }

  if (mapaNomes.has(chaveNome)) {
    return {
      encontrado: true,
      sigla: mapaNomes.get(chaveNome)
    };
  }

  if (mapaNomes.has(chaveSemParentesesNome)) {
    return {
      encontrado: true,
      sigla: mapaNomes.get(chaveSemParentesesNome)
    };
  }

  // ======================================================
  // 3. MATCH PARCIAL SEGURO
  // Só aplica para nomes longos, nunca para siglas curtas.
  // Evita erro tipo GLI virar A1GLI.
  // ======================================================

  if (chaveNome.length >= 8) {
    for (const [nomeNormalizado, sigla] of mapaNomes.entries()) {
      if (
        nomeNormalizado.length >= 8 &&
        (
          chaveNome.includes(nomeNormalizado) ||
          nomeNormalizado.includes(chaveNome)
        )
      ) {
        return {
          encontrado: true,
          sigla
        };
      }
    }
  }

  // ======================================================
  // 4. NÃO ENCONTRADO
  // Mantém o exame original
  // ======================================================

  return {
    encontrado: false,
    original
  };
}

const resultado = pacientes.map((item, index) => {
  const json = item.json;

  const examesOriginais = Array.isArray(json.EXAMES)
    ? json.EXAMES
    : String(json.EXAMES_TEXTO || "")
        .split(",")
        .map(e => e.trim())
        .filter(Boolean);

  const examesNormalizados = [];
  const examesNaoEncontrados = [];

  for (const exame of examesOriginais) {
    const convertido = converterExame(exame);

    if (convertido.encontrado) {
      examesNormalizados.push(convertido.sigla);
    } else {
      examesNaoEncontrados.push(convertido.original);
      examesNormalizados.push(
        String(convertido.original || "").toUpperCase()
      );
    }
  }

  return {
    json: {
      ...json,

      EXAMES: examesNormalizados,

      EXAMES_TEXTO: examesNormalizados.join(", "),

      EXAMES_NAO_ENCONTRADOS: examesNaoEncontrados,

      QTD_EXAMES: examesNormalizados.length,

      _idx: index + 1,

      _totalPacientes: pacientes.length
    }
  };
});

return resultado;

// ======================================================
// EXTRATOR OCR - PROTOCOLO DE ENVIO AO LABORATÓRIO
// ✅ Extrai pacientes da tabela markdown do OCR
// ✅ Retorna 1 item por paciente
// ✅ Remove valores entre colchetes dos exames
// ✅ Posto vem do nome do arquivo: P12 -> 12
// ✅ Data vem do texto ou do nome do arquivo
// ======================================================

const input = $input.first().json;

// ======================================================
// 1. PEGA NOME DO ARQUIVO
// ======================================================

let nomeArquivo = "";

try {
  nomeArquivo = String($("ENVIO").first().json.name || "");
} catch (e) {
  nomeArquivo = String(input.name || input.fileName || "");
}

// ======================================================
// 2. PEGA TEXTO OCR
// ======================================================

const textoOCR = String(
  input.extractedText ||
  input.text ||
  input.markdown ||
  (Array.isArray(input.pages)
    ? input.pages.map(p => p.markdown || "").join("\n")
    : "") ||
  ""
);

if (!textoOCR.trim()) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum texto OCR encontrado.",
        nomeArquivo
      }
    }
  ];
}

// ======================================================
// 3. FUNÇÕES AUXILIARES
// ======================================================

function limpar(valor) {
  return String(valor ?? "")
    .replace(/\u00A0/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizar(valor) {
  return limpar(valor)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function extrairPosto(nome, texto) {
  const fonte = `${nome || ""}\n${texto || ""}`;

  // Nome do arquivo: P12, P 12, P012
  let m = fonte.match(/\bP\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  // Rodapé: P: 12
  m = fonte.match(/\bP\s*:\s*0*(\d{1,5})\b/i);
  if (m) return m[1];

  return "";
}

function extrairData(nome, texto) {
  const fonte = `${nome || ""}\n${texto || ""}`;

  // DD/MM/AAAA
  let m = fonte.match(/\b(\d{2})\/(\d{2})\/(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // DD.MM.AAAA
  m = fonte.match(/\b(\d{2})\.(\d{2})\.(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  // DD-MM-AAAA
  m = fonte.match(/\b(\d{2})-(\d{2})-(\d{4})\b/);
  if (m) return `${m[1]}/${m[2]}/${m[3]}`;

  return "";
}

function removerValoresColchetes(texto) {
  return String(texto || "")
    .replace(/\[[^\]]*]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function separarExames(textoExames, posto) {
  let texto = removerValoresColchetes(textoExames);

  if (!texto) return [];

  // Regra específica solicitada anteriormente
  if (String(posto) === "137") {
    texto = texto.replace(/\bGLICOSE\s+JEJUM\b/gi, "GLI");
  }

  const exames = [];
  let atual = "";
  let nivelParenteses = 0;

  for (let i = 0; i < texto.length; i++) {
    const char = texto[i];

    if (char === "(") {
      nivelParenteses++;
      atual += char;
      continue;
    }

    if (char === ")") {
      nivelParenteses = Math.max(0, nivelParenteses - 1);
      atual += char;
      continue;
    }

    // Se tiver vírgula fora de parênteses, separa
    if (char === "," && nivelParenteses === 0) {
      const exame = limpar(atual);
      if (exame) exames.push(exame);
      atual = "";
      continue;
    }

    atual += char;
  }

  const ultimo = limpar(atual);
  if (ultimo) exames.push(ultimo);

  return exames
    .map(e => limpar(e))
    .filter(e => e)
    .filter(e => !/^\d+([.,]\d+)?$/.test(e));
}

function ehLinhaPaciente(cols) {
  if (cols.length < 5) return false;

  const codIntegracao = limpar(cols[0]);
  const codAtend = limpar(cols[1]);
  const paciente = limpar(cols[2]);
  const exames = limpar(cols[3]);

  if (!/^\d{6,}$/.test(codIntegracao)) return false;
  if (!/^\d{4,}$/.test(codAtend)) return false;
  if (!paciente || paciente.length < 5) return false;
  if (/\d/.test(paciente)) return false;
  if (!exames) return false;

  const nPaciente = normalizar(paciente);

  const bloqueados = [
    "PACIENTE",
    "COD INTEGRACAO",
    "COD ATEND",
    "EXAMES",
    "VALOR",
    "DESC CLI",
    "DESC LAB",
    "SALDO LAB"
  ];

  if (bloqueados.some(p => nPaciente.includes(p))) return false;

  return true;
}

// ======================================================
// 4. DADOS BASE
// ======================================================

const posto = extrairPosto(nomeArquivo, textoOCR);
const data = extrairData(nomeArquivo, textoOCR);

// ======================================================
// 5. EXTRAI LINHAS DA TABELA
// ======================================================

const linhas = textoOCR
  .split(/\r?\n/)
  .map(l => limpar(l))
  .filter(Boolean);

const pacientes = [];

for (const linha of linhas) {
  if (!linha.includes("|")) continue;

  // Remove bordas da tabela e preserva colunas vazias
  let cols = linha.split("|").map(c => limpar(c));

  // Remove primeira e última coluna vazias quando a linha começa/termina com |
  if (cols[0] === "") cols.shift();
  if (cols[cols.length - 1] === "") cols.pop();

  if (!ehLinhaPaciente(cols)) continue;

  const codIntegracao = limpar(cols[0]);
  const codAtend = limpar(cols[1]);
  const paciente = limpar(cols[2]).toUpperCase();
  const examesBruto = limpar(cols[3]);
  const valorLinha = limpar(cols[4]);

  const exames = separarExames(examesBruto, posto);

  if (exames.length === 0) continue;

  pacientes.push({
    codIntegracao,
    codAtend,
    PACIENTE: paciente,
    EXAMES: exames,
    valorLinha
  });
}

// ======================================================
// 6. RETORNO FINAL
// ======================================================

if (pacientes.length === 0) {
  return [
    {
      json: {
        sucesso: false,
        erro: true,
        mensagem: "Nenhum paciente foi extraído do OCR.",
        posto,
        data,
        nomeArquivo,
        debug: {
          totalLinhas: linhas.length,
          linhasComPipe: linhas.filter(l => l.includes("|")).length,
          primeirasLinhasComPipe: linhas.filter(l => l.includes("|")).slice(0, 5)
        }
      }
    }
  ];
}

const resultado = pacientes.map((p, index) => ({
  json: {
    sucesso: true,
    categoria: "(+)COMPUTADOR DO POSTO",
    PACIENTE: p.PACIENTE,
    EXAMES: p.EXAMES,
    EXAMES_TEXTO: p.EXAMES.join(", "),
    QTD_EXAMES: p.EXAMES.length,
    VALOR: 0,
    posto,
    data,
    codIntegracao: p.codIntegracao,
    codAtend: p.codAtend,
    valorLinha: p.valorLinha,
    _idx: index + 1,
    _totalPacientes: pacientes.length
  }
}));

return resultado;

const raw =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.content ||
  "";

let texto = String(raw).trim();

// =====================================
// REMOVE BLOCO MARKDOWN
