texto = texto
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "")
  .trim();

// =====================================
// REMOVE QUEBRAS E ESCAPES EXTRAS
// =====================================
texto = texto
  .replace(/\r/g, "")
  .replace(/\n/g, " ")
  .replace(/\t/g, " ")
  .trim();

// =====================================
// LOCALIZA ARRAY JSON
// =====================================
const inicio = texto.indexOf("[");
const fim = texto.lastIndexOf("]");

if (inicio === -1 || fim === -1) {
  throw new Error(
    "A IA não retornou um ARRAY JSON válido."
  );
}

let jsonTexto = texto.slice(inicio, fim + 1);

// =====================================
// REMOVE ESCAPES DUPLOS
// =====================================
if (jsonTexto.includes('\\"')) {
  jsonTexto = jsonTexto
    .replace(/\\"/g, '"')
    .replace(/\\\\/g, "\\");
}

// =====================================
// REMOVE ASPAS EXTERNAS
// =====================================
if (
  jsonTexto.startsWith('"[') &&
  jsonTexto.endsWith(']"')
) {
  jsonTexto = jsonTexto
    .slice(1, -1);
}

// =====================================
// CONVERTE JSON
// =====================================
let dados;

try {
  dados = JSON.parse(jsonTexto);
} catch (e) {

  // =====================================
  // TENTA NOVAMENTE COM JSON.parse DUPLO
  // =====================================
  try {
    dados = JSON.parse(
      JSON.parse(JSON.stringify(jsonTexto))
    );
  } catch (e2) {
    throw new Error(
      "Erro ao converter JSON da IA: " +
      e.message
    );
  }
}

// =====================================
// GARANTE ARRAY
// =====================================
if (!Array.isArray(dados)) {
  dados = [dados];
}

// =====================================
// NORMALIZA CAMPOS
// =====================================
const resultado = dados.map((item, index) => {

  const exames =
    Array.isArray(item.EXAMES)
      ? item.EXAMES
      : String(item.EXAMES || "")
          .split(",")
          .map(e => e.trim())
          .filter(Boolean);

  return {
    json: {
      sucesso: true,

      categoria:
        item.categoria ||
        "(+)COMPUTADOR DO POSTO",

      PACIENTE:
        String(item.PACIENTE || "").trim(),

      EXAMES: exames,

      EXAMES_TEXTO:
        exames.join(", "),

      QTD_EXAMES:
        exames.length,

      VALOR:
        Number(item.VALOR || 0),

      posto:
        String(
          item.posto || ""
        ).trim(),

      data:
        String(
          item.data || ""
        ).trim(),

      _idx: index + 1,

      _totalPacientes:
        dados.length
    }
  };
});

// =====================================
// REMOVE DUPLICADOS
// =====================================
const vistos = new Set();

const unicos = [];

for (const item of resultado) {

  const chave =
    `${item.json.PACIENTE}|${item.json.EXAMES_TEXTO}|${item.json.data}`;

  if (!vistos.has(chave)) {
    vistos.add(chave);
    unicos.push(item);
  }
